import { NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useState, useEffect } from "react";
import { localCart, localOrders } from "../services/api";

const Sidebar = ({ onToast, isOpen, setOpen }) => {
const { user, logout, sessionStart } = useAuth();
const navigate = useNavigate();

const [cartCount, setCartCount] = useState(0);
const [orderCount, setOrderCount] = useState(0);
const [elapsed, setElapsed] = useState("00:00");

// cart + orders count
useEffect(() => {
const updateCart = () =>
setCartCount(
localCart.get().reduce((s, i) => s + i.quantity, 0)
);

```
const updateOrders = () =>
  setOrderCount(localOrders.count());

updateCart();
updateOrders();

window.addEventListener("cartUpdated", updateCart);
window.addEventListener("ordersUpdated", updateOrders);

return () => {
  window.removeEventListener("cartUpdated", updateCart);
  window.removeEventListener("ordersUpdated", updateOrders);
};
```

}, []);

// session timer
useEffect(() => {
if (!sessionStart) return;

```
const start = sessionStart.getTime();

const t = setInterval(() => {
  const s = Math.floor(
    (Date.now() - start) / 1000
  );

  setElapsed(
    String(Math.floor(s / 60)).padStart(2, "0") +
      ":" +
      String(s % 60).padStart(2, "0")
  );
}, 1000);

return () => clearInterval(t);
```

}, [sessionStart]);

const handleLogout = () => {
logout();
onToast?.("Logged out", "info");
navigate("/");
};

const close = () => setOpen(false);

// ✅ GROUPED SIDEBAR
const navGroups = [
{
title: "SHOP",
items: [
{ to: "/dashboard", icon: "🏠", label: "Dashboard" },
{ to: "/products", icon: "🛍️", label: "Products" },
],
},

```
{
  title: "CART",
  items: [
    { to: "/cart", icon: "🛒", label: "Cart", badge: cartCount },
    { to: "/checkout", icon: "💳", label: "Checkout" },
  ],
},

{
  title: "ORDERS",
  items: [
    {
      to: "/orders",
      icon: "📦",
      label: "My Orders",
      badge: orderCount,
    },
    { to: "/journey", icon: "🗺️", label: "Journey" },
  ],
},
```

];

if (!user) return null;

return (
<>

```
  {/* MOBILE BAR */}
  <div
    className="d-flex d-lg-none align-items-center justify-content-between px-3 py-2"
    style={{
      position: "fixed",
      top: 0,
      left: 0,
      right: 0,
      zIndex: 1040,
      height: 52,
      background:
        "linear-gradient(90deg,#1a1200,#2d2000)",
    }}
  >
    <button
      className="btn btn-sm btn-outline-warning"
      onClick={() => setOpen(!isOpen)}
    >
      {isOpen ? "✕" : "☰"}
    </button>

    <div className="fw-bold text-warning">
      TechGear
    </div>

    <div>
      {cartCount > 0 && (
        <span className="badge bg-danger">
          {cartCount}
        </span>
      )}

      {orderCount > 0 && (
        <span className="badge bg-warning text-dark ms-1">
          {orderCount}
        </span>
      )}
    </div>
  </div>



  {/* SIDEBAR */}
  <div
    className="d-flex flex-column text-white"
    style={{
      width: 240,
      minHeight: "100vh",
      position: "fixed",
      top: 0,
      left: 0,
      zIndex: 1036,
      overflowY: "auto",
      background:
        "linear-gradient(180deg,#1a1200 0%,#2d2000 100%)",
      transform: isOpen
        ? "translateX(0)"
        : "translateX(-100%)",
      transition: "0.3s",
    }}
  >


    {/* LOGO */}
    <div className="p-3 text-center">
      <div style={{ fontSize: "2rem" }}>
        🛒
      </div>

      <div className="fw-bold text-warning">
        TechGear Store
      </div>

      <div
        style={{
          fontSize: 10,
          color: "gray",
          letterSpacing: 2,
        }}
      >
        USER PORTAL
      </div>
    </div>



    {/* USER */}
    <div className="px-3 py-3">
      <div>{user.name}</div>

      <div
        style={{
          fontSize: 12,
          color: "gray",
        }}
      >
        {user.email}
      </div>

      <span className="badge bg-success mt-2">
        ⏱ {elapsed}
      </span>
    </div>



    {/* NAV GROUPS */}
    <nav className="flex-grow-1">

      {navGroups.map((group) => (

        <div key={group.title}>

          <div
            style={{
              fontSize: 10,
              color: "#aaa",
              padding: "10px 15px 5px",
              letterSpacing: 2,
            }}
          >
            {group.title}
          </div>


          {group.items.map((item) => (

            <NavLink
              key={item.to}
              to={item.to}
              onClick={close}
              className={({ isActive }) =>
                "d-flex align-items-center px-3 py-2 text-decoration-none " +
                (isActive
                  ? "bg-warning text-dark"
                  : "text-white")
              }
            >

              <span style={{ width: 25 }}>
                {item.icon}
              </span>

              <span className="flex-grow-1">
                {item.label}
              </span>

              {item.badge > 0 && (
                <span className="badge bg-danger">
                  {item.badge}
                </span>
              )}

            </NavLink>

          ))}

        </div>

      ))}

    </nav>



    {/* LOGOUT */}
    <div className="p-3">

      <button
        className="btn btn-outline-warning w-100"
        onClick={handleLogout}
      >
        Sign Out
      </button>

    </div>


  </div>

</>

);
};

export default Sidebar;
